{ "title": str, "tldr": str, "problem_statement": str, "goals": [str], "non_goals": [str], "target_users": [{ "segment": str, "need": str }], "user_stories": [{ "as_a": str, "i_want": str, "so_that": str, "acceptance_criteria": [str] }], "proposed_solution": str, "success_metrics": [{ "metric": str, "target": str, "measurement": str }], "open_questions": [{ "question": str, "owner": str, "deadline": str }], "risks": [{ "risk": str, "mitigation": str }], "out_of_scope": [str] }

parameters.jsCode:
const brief = $('Normalise Brief').first().json;
let prd;
try { prd = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { prd = {}; }
return [{ json: { prd_id: brief.id, requested_by: brief.requested_by, created_at: brief.created_at, status: 'draft', ...prd } }];
